import type { ComponentType, SVGProps } from "react";

type TechIconProps = SVGProps<SVGSVGElement>;

type Tech = {
  name: string;
  Icon: ComponentType<TechIconProps>;
};

const technologies: Tech[] = [
  { name: "HTML", Icon: HtmlIcon },
  { name: "CSS", Icon: CssIcon },
  { name: "JavaScript", Icon: JavascriptIcon },
  { name: "React", Icon: ReactIcon },
  { name: "Tailwind", Icon: TailwindIcon },
  { name: "TypeScript", Icon: TypescriptIcon },
  { name: "Git", Icon: GitIcon },
  { name: "GitHub", Icon: GithubIcon },
  { name: "Next.js", Icon: NextIcon },
  { name: "SQL", Icon: SqlIcon },
];

export default function TechCarousel() {
  const visibleItems = [...technologies, ...technologies];

  return (
    <section className="w-full overflow-hidden bg-surface py-6 text-muted">
      <div className="relative flex overflow-hidden [mask-image:linear-gradient(to_right,transparent,black_12%,black_88%,transparent)]">
        <div className="tech-carousel-track flex w-max items-center will-change-transform">
          {[0, 1].map((groupIndex) => (
            <div
              key={groupIndex}
              className="flex min-w-max shrink-0 items-center gap-10 pr-10"
            >
              {visibleItems.map(({ name, Icon }, itemIndex) => {
                const isDuplicate =
                  groupIndex > 0 || itemIndex >= technologies.length;

                return (
                  <div
                    key={`${name}-${groupIndex}-${itemIndex}`}
                    aria-hidden={isDuplicate}
                    aria-label={!isDuplicate ? name : undefined}
                    title={!isDuplicate ? name : undefined}
                    className="flex h-10 md:h-12 lg:h-14 min-w-max items-center justify-center text-current transition-colors duration-300 hover:text-primary"
                  >
                    <Icon className="h-full w-auto" aria-hidden="true" />
                  </div>
                );
              })}
            </div>
          ))}
        </div>
      </div>

      <style>{`
        @keyframes tech-carousel-scroll {
          from {
            transform: translateX(0);
          }

          to {
            transform: translateX(-50%);
          }
        }

        .tech-carousel-track {
          animation: tech-carousel-scroll 36s linear infinite;
        }

        @media (prefers-reduced-motion: reduce) {
          .tech-carousel-track {
            animation: none;
          }
        }
      `}</style>
    </section>
  );
}

